nta.declaration:
/**
This case study has been published at "Correct System Design"
Symposium in Honor of Ernst-Rüdiger Olderog on the Occasion of
His 60th Birthday Oldenburg, Germany, September 8–9, 2015.

The paper "Safe and Optimal Adaptive Cruise Control" by 
Kim Guldstrand Larsen, Marius Mikucionis, Jakob Haahr Taankvist.

@incollection{cruise,
    year={2015},
    isbn={978-3-319-23505-9},
    booktitle={Correct System Design},
    volume={9360},
    series={Lecture Notes in Computer Science},
    editor={Meyer, Roland and Platzer, André and Wehrheim, Heike},
    doi={10.1007/978-3-319-23506-6_17},
    title={Safe and Optimal Adaptive Cruise Control},
    url={http://dx.doi.org/10.1007/978-3-319-23506-6_17},
    publisher={Springer International Publishing},
    author={Larsen, Kim Guldstrand and Miku\v{c}ionis, Marius and Taankvist, Jakob Haahr},
    pages={260-277},
    language={English}
}
*/
clock time;

const int fleetSize = %fleet size%;


/** Modified mechanics */

// t_act=0.8, distance_min=10.0, distance_max=90.0, acceleration=1.0, v_ego_min=0.0, v_ego_max=12.0, v_front_min=0.0, v_front_max=12.0
const double t_act_multiplier = 0.8;
const double acceleration_multiplier = 0.5;
const double distance_add = 25;
const double velocity_add = 10;

const double t_act = 1*t_act_multiplier;
// Abhorrent naming: `acc` is the constant determining the rate of acceleration. `acceleration` is an array containing the current accelerations of the cars in a given time-step.
const double acc = 2*acceleration_multiplier;
const double minDistance = (0 + distance_add)*t_act_multiplier*acceleration_multiplier;
const double maxDistance = (200 + distance_add)*t_act_multiplier*acceleration_multiplier;

const double minVelocity = (-10 + velocity_add)*t_act_multiplier*acceleration_multiplier;
const double maxVelocity = (20 + velocity_add)*t_act_multiplier*acceleration_multiplier;

/** End of modified mechanics. The rest of the stuff: */

double acceleration[fleetSize];   // acceleration of car
broadcast chan choose;    // signal for car to decide 
broadcast chan shield;  // Signal for shield to change unsafe actions
broadcast chan tick;    // Signal to check if distance greater than 200


hybrid clock velocity[fleetSize];   		// velocity of each car
hybrid clock distance[fleetSize - 1] = {%distances%};

hybrid clock D[fleetSize - 1]; 				// "cost" of distance used in strategy optimization

/* Hybrid clocks:
- Usually represent some continuous (dynamical) cost over the system state space.
- Can be used in rate (derivative) expressions.
- Cannot be used in constraints (guards and invariants).
- Are abstracted away and have no effect in symbolic analysis (Symbolic Simulator, queries like A[], E<>, TIGA safety synthesis)
- Are used in concrete simulations (Concrete Simulator, SMC queries like simulate, Pr, minE, maxE, E[...](max:)).      
*/



/** Pre-trained agent */

const int PositiveAcceleration = 1;
const int NegativeAcceleration = 0;
const int NoAcceleration = 2;

%imports%

int get_action(int i) {
    %agent selector%
        return fint(acceleration[-1]); // Provoke Error: No strategy loaded for i.
}

void preTrainedChoice(int i) {
    int action = get_action(i);
    if (action == NoAcceleration)
        acceleration[i] = 0;
    else if (action == PositiveAcceleration)
        acceleration[i] = acc;
    else
        acceleration[i] = -acc;

    if (velocity[i] <= minVelocity && action == NegativeAcceleration)
        acceleration[i] = 0;
    else if (velocity[i] >= maxVelocity && action == PositiveAcceleration)
        acceleration[i] = 0;
}

/** Shield */

import %shield path%
{
    int get_value(double velocity, double velocityFront, double distance);
};

const int shield_size_v = 15;
const int shield_size_d = 200;

const double granularity_v = (maxVelocity - minVelocity)/shield_size_v;
const double granularity_d = (maxDistance - minDistance)/shield_size_d;

typedef struct {
    bool backwards;
    bool neutral;
    bool forwards;
} allowedActions;

allowedActions intToActions(int bitarray) {
    allowedActions result = { 
        (0 != (bitarray & (1 << 0))),
        (0 != (bitarray & (1 << 1))),
        (0 != (bitarray & (1 << 2)))
    };
    return result;
}

int debugUnsafeState = 0;

double speedLimit(int i) {
    if (velocity[i] <= minVelocity && acceleration[i] < 0)
        return 0;
    else if (velocity[i] >= maxVelocity && acceleration [i] > 0)
        return 0;
    else
        return acceleration[i];
}

double backup_policy(allowedActions allowed) {
    if (allowed.forwards)
        return acc;
    else if (allowed.neutral)
        return 0;
    else if (allowed.backwards)
        return -acc;

    return acceleration[-1];    // Provoke error: No safe actions in this state.
}

double projection_v(double v) {
    return v/t_act_multiplier/acceleration_multiplier - velocity_add;
}

double projection_d(double d) {
    return d/t_act_multiplier/acceleration_multiplier - distance_add;
}

allowedActions debug1;
bool debugShieldApplied;

void apply_shield(int i) {
    double v = round(projection_v(velocity[i]));
    double vFront = round(projection_v(velocity[i - 1]));
    double d = round(projection_d(distance[i - 1]));
    allowedActions allowed = intToActions(get_value(v, vFront, d));
    debug1 = allowed;
    if (!allowed.forwards && !allowed.neutral && !allowed.backwards) {
        debugUnsafeState = 1;
        return;
    }
    if (acceleration[i] ==  acc && !allowed.forwards ||
        acceleration[i] ==  0 && !allowed.neutral ||
        acceleration[i] == -acc && !allowed.backwards) {
        acceleration[i] = backup_policy(allowed);
        debugShieldApplied = true;
    }
    acceleration[i] = speedLimit(i);
}
